INSERT INTO public.onboarding_phases (id, number, title, subtitle, day_range, description, milestones, sort_order) VALUES ('phase-0', 0, 'Preboarding', 'Before Day 1', 'Offer accepted → Day 0', 'Structured preboarding so you arrive informed, uniformed, and ready — not confused.', '[]'::jsonb, 0);
INSERT INTO public.onboarding_phase_role_copy (phase_id, role, description, milestones) VALUES ('phase-0', 'cook', 'Before Day 1, your outlet team prepares your kitchen station and training materials.', '[]'::jsonb);
INSERT INTO public.onboarding_phase_role_copy (phase_id, role, description, milestones) VALUES ('phase-0', 'cashier', 'Before Day 1, your outlet team prepares your POS access and front-of-house onboarding.', '[]'::jsonb);
INSERT INTO public.onboarding_phase_role_copy (phase_id, role, description, milestones) VALUES ('phase-0', 'supervisor', 'Before Day 1, your outlet team prepares your leadership onboarding path.', '[]'::jsonb);
INSERT INTO public.onboarding_sections (id, phase_id, title, subtitle, sort_order) VALUES ('preboarding-checklist', 'phase-0', 'Preboarding Checklist', '', 0);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t1', 'preboarding-checklist', 'Send offer letter and contract for signing', 'Formalises employment and creates legal clarity before Day 1.', NULL, 'EXCO', '{"all"}', 'internal', NULL, NULL, NULL, 0);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t2', 'preboarding-checklist', 'Collect required documents (IC, bank account, EPF number, tax number)', 'Enables payroll setup. Malaysia Employment Act requirement.', NULL, 'GM', '{"all"}', 'internal', NULL, NULL, NULL, 1);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t3', 'preboarding-checklist', 'Set up payroll and banking details in system', 'New hire must receive first pay on time. Late first pay damages trust immediately.', NULL, 'GM', '{"all"}', 'internal', NULL, NULL, NULL, 2);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t4', 'preboarding-checklist', 'WhatsApp ''Welcome to Quackteow'' message from EXCO', 'Sets the cultural tone. Shows you are expected and valued — not just processed.', NULL, 'EXCO', '{"all"}', 'internal', NULL, NULL, NULL, 3);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t5', 'preboarding-checklist', 'Share outlet address, parking info, dress code, and report-in time', 'Eliminates Day 1 anxiety about logistics.', NULL, 'GM', '{"all"}', 'internal', NULL, NULL, NULL, 4);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t6', 'preboarding-checklist', 'Prepare uniform in correct size', 'Uniform is part of brand identity (SOP §3.3). Arriving without one on Day 1 is a poor start.', NULL, 'SUP', '{"all"}', 'internal', NULL, NULL, NULL, 5);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t7', 'preboarding-checklist', 'Assign a ''Buddy'' from existing staff at the outlet', 'A peer buddy reduces social isolation in the first week.', NULL, 'SUP', '{"all"}', 'internal', NULL, NULL, NULL, 6);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t8', 'preboarding-checklist', 'Brief the buddy on their role and expectations', 'Unbriefed buddies may default to informal culture that contradicts SOP standards.', NULL, 'SUP', '{"all"}', 'internal', NULL, NULL, NULL, 7);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t9', 'preboarding-checklist', 'Create POS user account and assign access level', 'System access on Day 1 — not Day 3. Waiting wastes training time.', NULL, 'GM', '{"all"}', 'internal', NULL, NULL, NULL, 8);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t10', 'preboarding-checklist', 'Prepare new hire''s workstation / cooking station', 'Physical readiness signals: ''We were expecting you''.', NULL, 'SUP', '{"all"}', 'internal', NULL, NULL, NULL, 9);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t11', 'preboarding-checklist', 'Print and laminate Appendix A (Cooking Sequence) and Appendix B (Portion Card)', 'Reference materials should be physical and at-station from Day 1.', NULL, 'SUP', '{"cook"}', 'internal', NULL, NULL, NULL, 10);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p0-t12', 'preboarding-checklist', 'Print Training Sign-Off Form (Appendix E of SOP) — ready for Week 1', 'Having the form ready prevents supervisors from improvising assessments.', NULL, 'GM', '{"all"}', 'internal', NULL, NULL, NULL, 11);
INSERT INTO public.onboarding_phases (id, number, title, subtitle, day_range, description, milestones, sort_order) VALUES ('phase-1', 1, 'Orientation', 'Week 1 (Days 1–7)', 'Days 1–7', 'Week 1 is about foundation — not productivity. Build standards before speed.', '["Portion accuracy: 10/10 ingredients from §3.1","SS Bowl rule: zero egg cracked directly into wok","SOP awareness: 3 escalation scenarios explained","Checklist independence: opening or closing without prompting"]'::jsonb, 1);
INSERT INTO public.onboarding_phase_role_copy (phase_id, role, description, milestones) VALUES ('phase-1', 'cook', 'Your first week in the kitchen: learn portions, food safety, and cooking standards before speed.', '["Portion accuracy: 10/10 ingredients from §3.1","SS Bowl rule: zero egg cracked directly into wok","Plate your first orders under supervision","Complete opening or closing checklist without prompting"]'::jsonb);
INSERT INTO public.onboarding_phase_role_copy (phase_id, role, description, milestones) VALUES ('phase-1', 'cashier', 'Your first week on the floor: learn POS, order accuracy, and customer service before speed.', '["Read back every POS order accurately","Process 10+ transactions under supervision","Practice complaint response script (SOP §12.1)","Complete opening or closing checklist without prompting"]'::jsonb);
INSERT INTO public.onboarding_phase_role_copy (phase_id, role, description, milestones) VALUES ('phase-1', 'supervisor', 'Your first week on the supervisor track: learn outlet standards, escalation, and team routines.', '["SOP awareness: 3 escalation scenarios explained","Observe full opening and closing routines","Practice complaint response via role-play","Complete HACCP temperature log independently"]'::jsonb);
INSERT INTO public.onboarding_sections (id, phase_id, title, subtitle, sort_order) VALUES ('day-1', 'phase-1', 'Day 1 — First Impressions', 'All roles', 0);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d1-t1', 'day-1', 'Warm welcome by Supervisor at outlet entrance', NULL, 'SUP greets by name, introduces to the team, walks the full outlet before the station.', 'SUP', '{"all"}', 'hire', 'Meet your supervisor and team at the outlet entrance', NULL, 'Your supervisor will greet you by name, introduce you to the team, and walk the full outlet before your station.', 0);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d1-t2', 'day-1', 'Tour: kitchen, storage, chiller, POS, customer area, toilets', NULL, 'Point out SS bowl location, Quack Sos storage, and temperature log.', 'SUP', '{"all"}', 'hire', 'Complete your outlet tour with your supervisor', NULL, 'Note the SS bowl location, Quack Sos storage, and temperature log during your walkthrough.', 1);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d1-t3', 'day-1', 'Brand values conversation (not a lecture)', NULL, 'Discuss Quackteow''s origin, Quackmaster system, and the ''no eye-balling'' culture.', 'SUP', '{"all"}', 'hire', 'Learn Quackteow brand values with your supervisor', NULL, 'Ask questions about Quackteow''s origin, the Quackmaster system, and the ''no eye-balling'' culture.', 2);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d1-t4', 'day-1', 'Issue uniform, confirm fit, explain wear standards (SOP §3.3)', NULL, NULL, 'SUP', '{"all"}', 'hire', 'Receive your uniform and confirm fit (SOP §3.3)', NULL, NULL, 3);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d1-t5', 'day-1', 'SOP orientation: walk through Sections 3 and 4 together', NULL, 'Read §3.1 (portions) and §4 (food safety) aloud. Ask comprehension questions.', 'SUP', '{"all"}', 'hire', 'Complete SOP orientation on portions and food safety (§3 & §4)', NULL, 'Review §3.1 (portions) and §4 (food safety). Ask your supervisor if anything is unclear.', 4);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d1-t6', 'day-1', 'Introduce the Buddy — first meal together (outlet provides)', NULL, NULL, 'SUP', '{"all"}', 'hire', 'Meet your buddy over your first team meal', NULL, NULL, 5);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d1-t7', 'day-1', 'End-of-Day 1 check-in: ''How are you feeling? What was confusing?''', 'Early warning signals for onboarding gaps.', NULL, 'SUP', '{"all"}', 'hire', 'Complete your Day 1 check-in with your supervisor', 'Share anything confusing so your team can support you in Week 1.', NULL, 6);
