INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d23-t2', 'days-2-3', 'Shadow cashier for full service (FOH)', NULL, 'Read back each POS entry. Observe complaint response (SOP §12.1).', 'SUP', '{"cashier"}', 'hire', 'Shadow an experienced cashier for a full service shift', NULL, 'Read back each POS entry. Watch how complaints are handled (SOP §12.1).', 1);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d23-t3', 'days-2-3', 'Observe the full opening checklist being completed', NULL, 'Supervisor explains WHY each item matters, not just ticking it.', 'SUP', '{"all"}', 'hire', 'Observe the full opening checklist with your supervisor', NULL, 'Ask why each opening item matters — not just what to tick.', 2);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d23-t4', 'days-2-3', 'Observe closing checklist and cash reconciliation', NULL, 'Watch end-of-day reconciliation (SOP §11.3). Discuss variance scenarios.', 'SUP', '{"cashier","supervisor"}', 'hire', 'Observe closing checklist and cash reconciliation', NULL, 'Watch end-of-day reconciliation (SOP §11.3) and discuss variance scenarios.', 3);
INSERT INTO public.onboarding_tasks (id, section_id, title, why_it_matters, how_to, owner, roles, audience, title_hire, why_it_matters_hire, how_to_hire, sort_order) VALUES ('p1-d23-t5', 'days-2-3', 'Observe temperature log completion (SOP §4.2)', NULL, 'Learn probe thermometer use, breach identification, and response.', 'SUP', '{"all"}', 'hire', 'Learn how to complete the temperature log (SOP §4.2)', NULL, 'Practice probe thermometer use, breach identification, and response steps.', 4);
