INSERT INTO public.onboarding_phases (id, number, title, subtitle, day_range, description, milestones, sort_order) VALUES ('phase-2', 2, '30-Day Integration', 'Days 8–30', 'Days 8–30', 'Independent operation under guidance. Build speed, accuracy, and consistency.', '["Zero food safety violations across all shifts","Plate time ≤ 90 sec (TTDI/PJ/Hartamas) for 5 consecutive sessions","Cash variance within RM5 for 10 consecutive closings","Order accuracy ≥ 95% across 30 days"]'::jsonb, 2);
INSERT INTO public.onboarding_phase_role_copy (phase_id, role, description, milestones) VALUES ('phase-2', 'cook', 'Build kitchen speed and consistency while maintaining food safety every shift.', '["Zero food safety violations across all shifts","Plate time ≤ 90 sec for 5 consecutive sessions","Cook independently during off-peak periods"]'::jsonb);
